  INDEX `no_rkm_medis`(`no_rkm_medis` ASC) USING BTREE,
  INDEX `nota_piutang`(`no_rawat` ASC) USING BTREE,
  INDEX `besar_cicilan`(`besar_cicilan` ASC) USING BTREE,
  INDEX `catatan`(`catatan` ASC) USING BTREE,
  INDEX `kd_rek`(`kd_rek` ASC) USING BTREE,
  INDEX `kd_rek_kontra`(`kd_rek_kontra` ASC) USING BTREE,
  INDEX `kd_rek_diskon_piutang`(`kd_rek_diskon_piutang` ASC) USING BTREE,
  INDEX `kd_rek_tidak_terbayar`(`kd_rek_tidak_terbayar` ASC) USING BTREE,
  CONSTRAINT `bayar_piutang_ibfk_1` FOREIGN KEY (`no_rkm_medis`) REFERENCES `pasien` (`no_rkm_medis`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `bayar_piutang_ibfk_2` FOREIGN KEY (`kd_rek`) REFERENCES `rekening` (`kd_rek`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `bayar_piutang_ibfk_3` FOREIGN KEY (`kd_rek_kontra`) REFERENCES `rekening` (`kd_rek`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `bayar_piutang_ibfk_4` FOREIGN KEY (`kd_rek_diskon_piutang`) REFERENCES `rekening` (`kd_rek`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `bayar_piutang_ibfk_5` FOREIGN KEY (`kd_rek_tidak_terbayar`) REFERENCES `rekening` (`kd_rek`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE = InnoDB CHARACTER SET = latin1 COLLATE = latin1_swedish_ci ROW_FORMAT = COMPACT;

