  INDEX `alamat`(`alamat` ASC) USING BTREE,
  INDEX `kota`(`kota` ASC) USING BTREE,
  INDEX `no_telp`(`no_telp` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = latin1 COLLATE = latin1_swedish_ci ROW_FORMAT = COMPACT;

-- ----------------------------
