  `kuota` int NULL DEFAULT NULL,
  PRIMARY KEY (`kd_dokter`, `hari_kerja`, `jam_mulai`) USING BTREE,
  INDEX `kd_dokter`(`kd_dokter` ASC) USING BTREE,
  INDEX `kd_poli`(`kd_poli` ASC) USING BTREE,
