  INDEX `kode_penyebab`(`kode_penyebab` ASC) USING BTREE,
  INDEX `nik`(`nik` ASC) USING BTREE,
  INDEX `kode_cidera`(`kode_cidera` ASC) USING BTREE,
  INDEX `kode_luka`(`kode_luka` ASC) USING BTREE,
  INDEX `kode_dampak`(`kode_dampak` ASC) USING BTREE,
  INDEX `nik_timk3`(`nik_timk3` ASC) USING BTREE,
  INDEX `nik_pelapor`(`nik_pelapor` ASC) USING BTREE,
  INDEX `kode_bagian`(`kode_bagian` ASC) USING BTREE,
  CONSTRAINT `k3rs_peristiwa_ibfk_1` FOREIGN KEY (`kode_cidera`) REFERENCES `k3rs_jenis_cidera` (`kode_cidera`) ON DELETE RESTRICT ON UPDATE CASCADE,
