  CONSTRAINT `k3rs_peristiwa_ibfk_3` FOREIGN KEY (`kode_lokasi`) REFERENCES `k3rs_lokasi_kejadian` (`kode_lokasi`) ON DELETE RESTRICT ON UPDATE CASCADE,
