  INDEX `lama`(`lama` ASC) USING BTREE,
  INDEX `ttl_biaya`(`ttl_biaya` ASC) USING BTREE,
  INDEX `stts_pulang`(`stts_pulang` ASC) USING BTREE,
  INDEX `trf_kamar`(`trf_kamar` ASC) USING BTREE,
