  `dokter_pjanak` double NULL DEFAULT NULL,
  `dokter_umum` double NULL DEFAULT NULL,
  `kd_pj` char(3) CHARACTER SET latin1 COLLATE latin1_swedish_ci NULL DEFAULT NULL,
