  `penolong` varchar(20) CHARACTER SET latin1 COLLATE latin1_swedish_ci NULL DEFAULT NULL,
  `no_skl` varchar(30) CHARACTER SET latin1 COLLATE latin1_swedish_ci NULL DEFAULT NULL,
  `g` varchar(10) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `p` varchar(10) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `a` varchar(10) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `f1` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `u1` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `t1` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `r1` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `w1` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `n1` varchar(20) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `f5` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `u5` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `t5` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `r5` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `w5` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `n5` varchar(2) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `f10` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `u10` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `t10` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `r10` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `w10` varchar(1) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `n10` varchar(2) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `resusitas` varchar(100) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `obat_diberikan` varchar(300) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `mikasi` varchar(100) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
  `mikonium` varchar(100) CHARACTER SET latin1 COLLATE latin1_swedish_ci NOT NULL,
