  INDEX `umur_ibu`(`umur_ibu` ASC) USING BTREE,
  INDEX `umur_ayah`(`umur_ayah` ASC) USING BTREE,
  INDEX `berat_badan`(`berat_badan` ASC) USING BTREE,
  INDEX `panjang_badan`(`panjang_badan` ASC) USING BTREE,
  INDEX `lingkar_kepala`(`lingkar_kepala` ASC) USING BTREE,
  INDEX `proses_lahir`(`proses_lahir` ASC) USING BTREE,
  INDEX `anakke`(`anakke` ASC) USING BTREE,
  INDEX `jam_lahir`(`jam_lahir` ASC) USING BTREE,
  INDEX `keterangan`(`keterangan` ASC) USING BTREE,
  INDEX `penolong`(`penolong` ASC) USING BTREE,
  CONSTRAINT `pasien_bayi_ibfk_1` FOREIGN KEY (`no_rkm_medis`) REFERENCES `pasien` (`no_rkm_medis`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `pasien_bayi_ibfk_2` FOREIGN KEY (`penolong`) REFERENCES `pegawai` (`nik`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE = InnoDB CHARACTER SET = latin1 COLLATE = latin1_swedish_ci ROW_FORMAT = COMPACT;

