  PRIMARY KEY (`no_faktur`) USING BTREE,
  INDEX `kode_suplier`(`kode_suplier` ASC) USING BTREE,
  INDEX `nip`(`nip` ASC) USING BTREE,
  INDEX `kd_bangsal`(`kd_bangsal` ASC) USING BTREE,
